        let result = verifier.extract_token_from_header("Token abc123");
        assert!(matches!(result, Err(JwtError::InvalidAuthorizationFormat)));

        let result = verifier.extract_token_from_header("abc123");
        assert!(matches!(result, Err(JwtError::InvalidAuthorizationFormat)));
