fn main() {
    use jsonwebtoken::{encode, EncodingKey, Header};
    use std::time::{SystemTime, UNIX_EPOCH};

    let secret = "my-super-secret-key-for-demo";

    // Create a sample JWT
    let now = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs() as usize;

    let claims = Claims {
        sub: "user-42".to_string(),
        exp: now + 3600,
        iat: Some(now),
        nbf: None,
        iss: Some("my-auth-service".to_string()),
        aud: None,
        email: Some("alice@example.com".to_string()),
        name: Some("Alice Wonderland".to_string()),
        roles: Some(vec!["admin".to_string(), "editor".to_string()]),
        extra: HashMap::new(),
    };

    let token = encode(
        &Header::new(Algorithm::HS256),
        &claims,
        &EncodingKey::from_secret(secret.as_bytes()),
    )
    .expect("Failed to create token");

    println!("Generated JWT: {}", &token[..50]);
    println!("...");

    // Verify using the convenience function
    match verify_jwt_hmac(&token, secret) {
        Ok(user) => {
            println!("\n=== Token Verified Successfully ===");
            println!("User ID: {}", user.user_id);
            println!("Email: {:?}", user.email);
            println!("Name: {:?}", user.name);
            println!("Roles: {:?}", user.roles);
        }
        Err(e) => {
            println!("Verification failed: {}", e);
        }
    }

    // Simulate HTTP request verification
    let mut headers = HashMap::new();
    headers.insert(
        "Authorization".to_string(),
        format!("Bearer {}", token),
    );

    let config = JwtVerifierConfig {
        allowed_algorithms: vec![Algorithm::HS256, Algorithm::HS384, Algorithm::HS512],
        signing_key: SigningKeyConfig::Secret(secret.to_string()),
        required_issuer: Some("my-auth-service".to_string()),
        leeway_seconds: 60,
        validate_exp: true,
        validate_nbf: true,
        required_audience: None,
    };

    let verifier = JwtVerifier::new(config);

    match verifier.verify_from_request_headers(&headers) {
        Ok(user) => {
            println!("\n=== HTTP Request Verified ===");
            println!("User ID: {}", user.user_id);
            println!("Email: {:?}", user.email);
            println!("Name: {:?}", user.name);
            println!("Roles: {:?}", user.roles);
            println!("Issuer: {:?}", user.claims.iss);
        }
        Err(e) => {
            println!("HTTP request verification failed: {}", e);
        }
    }
}